
var appid = "com.ss.iphone.ugc.Ame"
//各种弹窗，点击确认或者取消
function autoHandleAlert() {

}

// 关闭各种带有叉的提示
function autoCloseAlert() {
    //出现安全检查
    var res = wda.findImage("", 0.8, [120, 320, 140, 100]);
    if (res.found) {
        //右边黑色叉，白底
        var res = wda.findImage("", 0.8, [310, 20, 60, 600]);
        if (res.found) {
            if (res.found) wda.tap(res.value.x + wda.randomInt(0, res.value.width || 0), res.value.y + wda.randomInt(0, res.value.height || 0));
        }
    }
    //弹出网络访问，默认点击wlan与蜂窝网络
    var res = wda.findImage("", 0.8, [100, 230, 180, 250]);
    if (res.found) {
        if (res.found) wda.tap(res.value.x + wda.randomInt(0, res.value.width || 0), res.value.y + wda.randomInt(0, res.value.height || 0));
    }
    //右边黑色叉，白底
    var res = wda.findImage("", 0.8, [310, 20, 60, 600]);
    if (res.found) {
        wda.log("成功点击：右边黑色叉，白底");
        if (res.found) wda.tap(res.value.x + wda.randomInt(0, res.value.width || 0), res.value.y + wda.randomInt(0, res.value.height || 0));
    }
    // 3. 找完图记得清缓存
    wda.clearScreenshotCache();
}

var islogin = true;
//判断是否登录
function isLogin() {
    //如果出现红色按钮‘Log masuk’，说明未登录
    wda.log("查找按钮Log masuk");
    var res = wda.findImage("", 0.8, [130, 333, 110, 100]);
    if (res.found) {
        islogin = false;
    }

    //红色按钮‘Inicio de sesión’，说明未登录
    if (islogin) {
        wda.log("查找按钮Inicio de sesión");
        var res = wda.findImage("", 0.8, [100, 300, 200, 200]);
        if (res.found) {

            islogin = false;
        }
    }
    //出现选择登录方式
    if (islogin) {
        wda.log("出现选择登录方式");
        var res = wda.findImage("", 0.8, [35, 150, 50, 130]);
        if (res.found) {
            islogin = false;
        }
    }

    //弹窗账号状态提示框
    if (islogin) {
        wda.log("弹窗账号状态提示框");
        var res = wda.findImage("", 0.8, [60, 200, 300, 300]);
        if (res.found) {
            islogin = false;
            wda.tap(res.value.x + wda.randomInt(0, 300 || 0), res.value.y + 118 + wda.randomInt(0, 20 || 0));
        }
    }
    // 3. 找完图记得清缓存
    wda.clearScreenshotCache();
}

